'use client'
import { cn, useSignal, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import type { ButtonHTMLAttributes } from 'react'
import styles from './copy-button.module.css'

export interface CopyButtonProps extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, 'value'> {
  /** The text written to the clipboard on click. */
  value: string
  size?: 'sm' | 'md'
  labels?: { copy?: string; copied?: string }
}

export function CopyButton({ value, size = 'md', labels, className, ...props }: CopyButtonProps) {
  useSignals()
  const copied = useSignal(false)
  const copyLabel = labels?.copy ?? t(builtin.copyButton.copy)
  const copiedLabel = labels?.copied ?? t(builtin.copyButton.copied)

  const handleClick = () => {
    void navigator.clipboard.writeText(value)
    copied.value = true
    setTimeout(() => {
      copied.value = false
    }, 2000)
  }

  return (
    <button
      type="button"
      aria-label={copied.value ? copiedLabel : copyLabel}
      data-state={copied.value ? 'copied' : 'idle'}
      data-size={size}
      className={cn(styles['copyButton'], className)}
      onClick={handleClick}
      {...props}
    >
      {copied.value ? (
        <svg aria-hidden="true" viewBox="0 0 16 16" className={styles['icon']}>
          <path
            d="M13.5 4.5 6 12 2.5 8.5"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      ) : (
        <svg aria-hidden="true" viewBox="0 0 16 16" className={styles['icon']}>
          <rect
            x="5.5"
            y="5.5"
            width="8"
            height="8"
            rx="1.5"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
          />
          <path
            d="M3.5 10.5h-1a1 1 0 0 1-1-1v-7a1 1 0 0 1 1-1h7a1 1 0 0 1 1 1v1"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
          />
        </svg>
      )}
    </button>
  )
}

@layer cascivo.component {
  .copyButton {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background-color: var(--cascivo-color-surface);
    color: var(--cascivo-color-text-subtle);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      background-color: var(--cascivo-color-bg-subtle);
      color: var(--cascivo-color-text);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }

    &[data-state='copied'] {
      color: var(--cascivo-color-success);
    }

    &[data-size='sm'] {
      inline-size: var(--cascivo-control-height-sm);
      block-size: var(--cascivo-control-height-sm);
    }

    &[data-size='md'] {
      inline-size: var(--cascivo-control-height-md);
      block-size: var(--cascivo-control-height-md);
    }
  }

  .icon {
    inline-size: 1rem;
    block-size: 1rem;
  }
}
